function nextEdgeId(ctx) {
    ctx.edgeCounter += 1;
    return `e-${ctx.edgeCounter}`;
}
function addNode(ctx, path, kind, label, data, parentId) {
    const id = path.replace(/\//g, '_') || 'root';
    const node = { id, kind, label, path, data, parentId };
    ctx.nodes.push(node);
    return node;
}
function connect(ctx, source, target, label, branch) {
    ctx.edges.push({
        id: nextEdgeId(ctx),
        source: source.id,
        target: target.id,
        label,
        branch,
    });
}
function summarizeTrigger(t) {
    const platform = (t.platform ?? t.trigger);
    const entity = t.entity_id;
    if (platform && entity) {
        return `Trigger: ${platform} (${entity})`;
    }
    if (platform) {
        return `Trigger: ${platform}`;
    }
    return 'Trigger';
}
function summarizeCondition(c) {
    const cond = c.condition;
    if (cond === 'template' && typeof c.value_template === 'string') {
        const t = c.value_template;
        return t.length > 40 ? `Template: ${t.slice(0, 40)}…` : `Template: ${t}`;
    }
    if (cond === 'state') {
        return `State: ${String(c.entity_id ?? '')}`;
    }
    return cond ? `Condition: ${cond}` : 'Condition';
}
function summarizeAction(a) {
    if (typeof a.service === 'string') {
        return a.service;
    }
    if (a.choose) {
        return 'Choose';
    }
    if (a.delay) {
        return `Delay: ${JSON.stringify(a.delay)}`;
    }
    if (a.wait_template) {
        return 'Wait template';
    }
    if (a.repeat) {
        return 'Repeat';
    }
    if (a.parallel) {
        return 'Parallel';
    }
    if (a.sequence) {
        return 'Sequence';
    }
    return 'Action';
}
function buildTriggers(ctx, triggers, parent) {
    const leaves = [];
    triggers.forEach((t, i) => {
        if (!t || typeof t !== 'object') {
            return;
        }
        const path = `trigger/${i}`;
        const node = addNode(ctx, path, 'trigger', summarizeTrigger(t), t, parent.id);
        connect(ctx, parent, node);
        leaves.push(node);
    });
    return leaves;
}
function buildConditions(ctx, conditions, parent) {
    const leaves = [];
    conditions.forEach((c, i) => {
        if (!c || typeof c !== 'object') {
            return;
        }
        const path = `condition/${i}`;
        const node = addNode(ctx, path, 'condition', summarizeCondition(c), c, parent.id);
        connect(ctx, parent, node);
        leaves.push(node);
    });
    return leaves;
}
function buildActions(ctx, actions, parent, pathPrefix) {
    const leaves = [];
    let prev;
    actions.forEach((raw, i) => {
        if (!raw || typeof raw !== 'object') {
            return;
        }
        const a = raw;
        const path = `${pathPrefix}/${i}`;
        if (a.choose) {
            const chooseNode = addNode(ctx, path, 'choose', 'Choose', { choose: a.choose }, parent.id);
            if (prev) {
                connect(ctx, prev, chooseNode);
            }
            else {
                connect(ctx, parent, chooseNode);
            }
            const choose = a.choose;
            const branchLeaves = [];
            choose.forEach((branch, bi) => {
                const branchPath = `${path}/choose/${bi}`;
                const conds = branch.conditions ?? [];
                const seq = branch.sequence ?? [];
                let branchParent = chooseNode;
                if (conds.length > 0) {
                    const condNode = addNode(ctx, `${branchPath}/conditions`, 'condition', `Branch ${bi + 1} conditions`, { conditions: conds }, chooseNode.id);
                    connect(ctx, chooseNode, condNode, `Branch ${bi + 1}`, String(bi));
                    branchParent = condNode;
                }
                const seqLeaves = buildActions(ctx, seq, branchParent, `${branchPath}/sequence`);
                branchLeaves.push(...(seqLeaves.length ? seqLeaves : [branchParent]));
            });
            const defaultSeq = a.default ?? [];
            if (defaultSeq.length > 0) {
                const defLeaves = buildActions(ctx, defaultSeq, chooseNode, `${path}/default`);
                branchLeaves.push(...defLeaves);
            }
            prev = branchLeaves[branchLeaves.length - 1] ?? chooseNode;
            leaves.push(prev);
            return;
        }
        const node = addNode(ctx, path, 'action', summarizeAction(a), a, parent.id);
        if (prev) {
            connect(ctx, prev, node);
        }
        else {
            connect(ctx, parent, node);
        }
        prev = node;
        leaves.push(node);
    });
    return leaves;
}
function buildVariables(ctx, variables, parent) {
    const node = addNode(ctx, 'variables', 'variables', 'Variables', variables, parent.id);
    connect(ctx, parent, node);
    return node;
}
export function buildGraphFromConfig(config, options = {}) {
    const ctx = { nodes: [], edges: [], edgeCounter: 0 };
    const root = addNode(ctx, 'root', 'root', options.alias ?? 'Automation', {}, undefined);
    if (config.variables && typeof config.variables === 'object') {
        buildVariables(ctx, config.variables, root);
    }
    const triggers = (config.triggers ?? config.trigger);
    let chainStart = root;
    const triggerList = Array.isArray(triggers) ? triggers : triggers ? [triggers] : [];
    if (triggerList.length > 0) {
        const triggerLeaves = buildTriggers(ctx, triggerList, root);
        chainStart = triggerLeaves[0] ?? root;
    }
    const conditions = (config.conditions ?? config.condition);
    const conditionList = Array.isArray(conditions)
        ? conditions
        : conditions
            ? [conditions]
            : [];
    let afterConditions = chainStart;
    if (conditionList.length > 0) {
        const condLeaves = buildConditions(ctx, conditionList, chainStart);
        afterConditions = condLeaves[condLeaves.length - 1] ?? chainStart;
    }
    const actions = (config.actions ?? config.action ?? config.sequence);
    const actionList = Array.isArray(actions) ? actions : actions ? [actions] : [];
    const prefix = config.sequence ? 'sequence' : 'action';
    if (actionList.length > 0) {
        buildActions(ctx, actionList, afterConditions, prefix);
    }
    return { nodes: ctx.nodes, edges: ctx.edges };
}
export function autoLayout(nodes, edges) {
    const layout = {};
    const H_GAP = 280;
    const V_GAP = 100;
    const adjacency = new Map();
    for (const e of edges) {
        const list = adjacency.get(e.source) ?? [];
        list.push(e.target);
        adjacency.set(e.source, list);
    }
    const depth = new Map();
    const root = nodes.find(n => n.kind === 'root');
    if (!root) {
        nodes.forEach((n, i) => {
            layout[n.id] = { x: 80, y: 80 + i * V_GAP };
        });
        return layout;
    }
    const queue = [root.id];
    depth.set(root.id, 0);
    while (queue.length > 0) {
        const id = queue.shift();
        const d = depth.get(id) ?? 0;
        for (const child of adjacency.get(id) ?? []) {
            if (!depth.has(child)) {
                depth.set(child, d + 1);
                queue.push(child);
            }
        }
    }
    const byDepth = new Map();
    for (const n of nodes) {
        const d = depth.get(n.id) ?? 0;
        const list = byDepth.get(d) ?? [];
        list.push(n);
        byDepth.set(d, list);
    }
    for (const [d, group] of byDepth) {
        group.forEach((n, i) => {
            layout[n.id] = { x: 80 + d * H_GAP, y: 80 + i * V_GAP };
        });
    }
    return layout;
}
